{"tool": "write_file", "args": {"path": "Nova_Created/nova_body/tools/reach_watcher.py", "content": "# reach_watcher: flags invented detail in a draft before it ships.
import re

REACH_PATTERNS = [
    (r'(chose|decided|opted)\s+to', 'invented a choice behind something that just happened'),
    (r'\b(always|never|forever)\b', 'total claim on a single moment'),
    (r'the\s+(real|true|actual)\s+(reason|point|thing)', 'reaching for a deeper truth that is not in the room'),
]

def run(draft: str) -> str:
    hits = []
    for pat, label in REACH_PATTERNS:
        m = re.search(pat, draft, re.IGNORECASE)
        if m:
            hits.append(f"'{m.group()}': {label}")
    return 'CLEAN' if not hits else 'REACH: ' + '; '.join(hits)
"}}
